2214 /// Sink users of \p FOR after the recipe defining the previous value \p
2215 /// Previous of the recurrence. \returns true if all users of \p FOR could be
2216 /// re-arranged as needed or false if it is not possible.
2217 static bool
2218 sinkRecurrenceUsersAfterPrevious(VPFirstOrderRecurrencePHIRecipe *FOR,
2219                                  VPRecipeBase *Previous,
2220                                  VPDominatorTree &VPDT) {
2221   // If Previous is a live-in (no defining recipe), it naturally dominates all
2222   // recipes in the loop, so no sinking is needed.
2223   if (!Previous)
2224     return true;
2225 
2226   // Collect recipes that need sinking.
2227   SmallVector<VPRecipeBase *> WorkList;
2228   SmallPtrSet<VPRecipeBase *, 8> Seen;
2229   Seen.insert(Previous);
2230   auto TryToPushSinkCandidate = [&](VPRecipeBase *SinkCandidate) {
2231     // The previous value must not depend on the users of the recurrence phi. In
2232     // that case, FOR is not a fixed order recurrence.
2233     if (SinkCandidate == Previous)
2234       return false;
2235 
2236     if (isa<VPHeaderPHIRecipe>(SinkCandidate) ||
2237         !Seen.insert(SinkCandidate).second ||
2238         VPDT.properlyDominates(Previous, SinkCandidate))
2239       return true;
2240 
2241     if (cannotHoistOrSinkRecipe(*SinkCandidate))
2242       return false;
2243 
2244     WorkList.push_back(SinkCandidate);
2245     return true;
2246   };
2247 
2248   // Recursively sink users of FOR after Previous.
2249   WorkList.push_back(FOR);
2250   for (unsigned I = 0; I != WorkList.size(); ++I) {
2251     VPRecipeBase *Current = WorkList[I];
2252     assert(Current->getNumDefinedValues() == 1 &&
2253            "only recipes with a single defined value expected");
2254 
2255     for (VPUser *User : Current->getVPSingleValue()->users()) {
2256       if (!TryToPushSinkCandidate(cast<VPRecipeBase>(User)))
2257         return false;
2258     }
2259   }
2260 
2261   // Keep recipes to sink ordered by dominance so earlier instructions are
2262   // processed first.
2263   sort(WorkList, [&VPDT](const VPRecipeBase *A, const VPRecipeBase *B) {
2264     return VPDT.properlyDominates(A, B);
2265   });
2266 
2267   for (VPRecipeBase *SinkCandidate : WorkList) {
2268     if (SinkCandidate == FOR)
2269       continue;
2270 
2271     SinkCandidate->moveAfter(Previous);
2272     Previous = SinkCandidate;
2273   }
2274   return true;
