2374 bool VPlanTransforms::adjustFixedOrderRecurrences(VPlan &Plan,
2375                                                   VPBuilder &LoopBuilder) {
2376   VPDominatorTree VPDT(Plan);
2377 
2378   SmallVector<VPFirstOrderRecurrencePHIRecipe *> RecurrencePhis;
2379   for (VPRecipeBase &R :
2380        Plan.getVectorLoopRegion()->getEntry()->getEntryBasicBlock()->phis())
2381     if (auto *FOR = dyn_cast<VPFirstOrderRecurrencePHIRecipe>(&R))
2382       RecurrencePhis.push_back(FOR);
2383 
2384   for (VPFirstOrderRecurrencePHIRecipe *FOR : RecurrencePhis) {
2385     SmallPtrSet<VPFirstOrderRecurrencePHIRecipe *, 4> SeenPhis;
2386     VPRecipeBase *Previous = FOR->getBackedgeValue()->getDefiningRecipe();
2387     // Fixed-order recurrences do not contain cycles, so this loop is guaranteed
2388     // to terminate.
2389     while (auto *PrevPhi =
2390                dyn_cast_or_null<VPFirstOrderRecurrencePHIRecipe>(Previous)) {
2391       assert(PrevPhi->getParent() == FOR->getParent());
2392       assert(SeenPhis.insert(PrevPhi).second);
2393       Previous = PrevPhi->getBackedgeValue()->getDefiningRecipe();
2394     }
2395 
2396     if (!sinkRecurrenceUsersAfterPrevious(FOR, Previous, VPDT) &&
2397         !hoistPreviousBeforeFORUsers(FOR, Previous, VPDT))
2398       return false;
2399 
2400     // Introduce a recipe to combine the incoming and previous values of a
2401     // fixed-order recurrence.
2402     VPBasicBlock *InsertBlock =
2403         Previous ? Previous->getParent() : FOR->getParent();
2404     if (!Previous || isa<VPHeaderPHIRecipe>(Previous))
2405       LoopBuilder.setInsertPoint(InsertBlock, InsertBlock->getFirstNonPhi());
2406     else
2407       LoopBuilder.setInsertPoint(InsertBlock,
2408                                  std::next(Previous->getIterator()));
2409 
2410     auto *RecurSplice =
2411         LoopBuilder.createNaryOp(VPInstruction::FirstOrderRecurrenceSplice,
2412                                  {FOR, FOR->getBackedgeValue()});
2413 
2414     FOR->replaceAllUsesWith(RecurSplice);
2415     // Set the first operand of RecurSplice to FOR again, after replacing
2416     // all users.
2417     RecurSplice->setOperand(0, FOR);
2418 
2419     // Check for users extracting at the penultimate active lane of the FOR.
2420     // If only a single lane is active in the current iteration, we need to
2421     // select the last element from the previous iteration (from the FOR phi
2422     // directly).
2423     for (VPUser *U : RecurSplice->users()) {
2424       if (!match(U, m_ExtractLane(m_LastActiveLane(m_VPValue()),
2425                                   m_Specific(RecurSplice))))
2426         continue;
2427 
2428       VPBuilder B(cast<VPInstruction>(U));
2429       VPValue *LastActiveLane = cast<VPInstruction>(U)->getOperand(0);
2430       Type *I64Ty = Type::getInt64Ty(Plan.getContext());
2431       VPValue *Zero = Plan.getOrAddLiveIn(ConstantInt::get(I64Ty, 0));
2432       VPValue *One = Plan.getOrAddLiveIn(ConstantInt::get(I64Ty, 1));
2433       VPValue *PenultimateIndex = B.createSub(LastActiveLane, One);
2434       VPValue *PenultimateLastIter =
2435           B.createNaryOp(VPInstruction::ExtractLane,
2436                          {PenultimateIndex, FOR->getBackedgeValue()});
2437       VPValue *LastPrevIter =
2438           B.createNaryOp(VPInstruction::ExtractLastLane, FOR);
2439 
2440       VPValue *Cmp = B.createICmp(CmpInst::ICMP_EQ, LastActiveLane, Zero);
2441       VPValue *Sel = B.createSelect(Cmp, LastPrevIter, PenultimateLastIter);
2442       cast<VPInstruction>(U)->replaceAllUsesWith(Sel);
2443     }
2444   }
2445   return true;
2446 }
