160 Type *VPTypeAnalysis::inferScalarTypeForRecipe(const VPWidenRecipe *R) {
161   unsigned Opcode = R->getOpcode();
162   if (Instruction::isBinaryOp(Opcode) || Instruction::isShift(Opcode) ||
163       Instruction::isBitwiseLogicOp(Opcode)) {
164     Type *ResTy = inferScalarType(R->getOperand(0));
165     assert(ResTy == inferScalarType(R->getOperand(1)) &&
166            "types for both operands must match for binary op");
167     CachedTypes[R->getOperand(1)] = ResTy;
168     return ResTy;
169   }
170 
171   switch (Opcode) {
172   case Instruction::ICmp:
173   case Instruction::FCmp:
174     return IntegerType::get(Ctx, 1);
175   case Instruction::FNeg:
176   case Instruction::Freeze:
177     return inferScalarType(R->getOperand(0));
178   case Instruction::ExtractValue: {
179     assert(R->getNumOperands() == 2 && "expected single level extractvalue");
180     auto *StructTy = cast<StructType>(inferScalarType(R->getOperand(0)));
181     return StructTy->getTypeAtIndex(
182         cast<VPConstantInt>(R->getOperand(1))->getZExtValue());
