184   case Instruction::Select: {
185     Type *ResTy = inferScalarType(R->getOperand(1));
186     VPValue *OtherV = R->getOperand(2);
187     assert(inferScalarType(OtherV) == ResTy &&
188            "different types inferred for different operands");
189     CachedTypes[OtherV] = ResTy;
190     return ResTy;
191   }
192   default:
193     break;
194   }
195 
196   // Type inference not implemented for opcode.
197   LLVM_DEBUG({
198     dbgs() << "LV: Found unhandled opcode for: ";
199     R->getVPSingleValue()->dump();
