215 Type *VPTypeAnalysis::inferScalarTypeForRecipe(const VPReplicateRecipe *R) {
216   unsigned Opcode = R->getUnderlyingInstr()->getOpcode();
217 
218   if (Instruction::isBinaryOp(Opcode) || Instruction::isShift(Opcode) ||
219       Instruction::isBitwiseLogicOp(Opcode)) {
220     Type *ResTy = inferScalarType(R->getOperand(0));
221     assert(ResTy == inferScalarType(R->getOperand(1)) &&
222            "inferred types for operands of binary op don't match");
223     CachedTypes[R->getOperand(1)] = ResTy;
224     return ResTy;
225   }
226 
227   if (Instruction::isCast(Opcode))
228     return R->getUnderlyingInstr()->getType();
229 
230   switch (Opcode) {
231   case Instruction::Call: {
232     unsigned CallIdx = R->getNumOperands() - (R->isPredicated() ? 2 : 1);
233     return cast<Function>(R->getOperand(CallIdx)->getLiveInIRValue())
234         ->getReturnType();
235   }
236   case Instruction::Select: {
237     Type *ResTy = inferScalarType(R->getOperand(1));
238     assert(ResTy == inferScalarType(R->getOperand(2)) &&
239            "inferred types for operands of select op don't match");
240     CachedTypes[R->getOperand(2)] = ResTy;
241     return ResTy;
242   }
243   case Instruction::ICmp:
244   case Instruction::FCmp:
245     return IntegerType::get(Ctx, 1);
246   case Instruction::Alloca:
247   case Instruction::ExtractValue:
248     return R->getUnderlyingInstr()->getType();
249   case Instruction::Freeze:
250   case Instruction::FNeg:
251   case Instruction::GetElementPtr:
252     return inferScalarType(R->getOperand(0));
253   case Instruction::Load:
254     return cast<LoadInst>(R->getUnderlyingInstr())->getType();
255   case Instruction::Store:
256     // FIXME: VPReplicateRecipes with store opcodes still define a result
257     // VPValue, so we need to handle them here. Remove the code here once this
258     // is modeled accurately in VPlan.
259     return Type::getVoidTy(Ctx);
260   default:
261     break;
262   }
263   // Type inference not implemented for opcode.
264   LLVM_DEBUG({
265     dbgs() << "LV: Found unhandled opcode for: ";
266     R->getVPSingleValue()->dump();
267   });
268   llvm_unreachable("Unhandled opcode");
269 }
