271 Type *VPTypeAnalysis::inferScalarType(const VPValue *V) {
272   if (Type *CachedTy = CachedTypes.lookup(V))
273     return CachedTy;
274 
275   if (auto *IRV = dyn_cast<VPIRValue>(V))
276     return IRV->getType();
277 
278   if (isa<VPSymbolicValue>(V)) {
279     // All VPValues without any underlying IR value (like the vector trip count
280     // or the backedge-taken count) have the same type as the canonical IV.
281     return CanonicalIVTy;
282   }
283 
284   Type *ResultTy =
285       TypeSwitch<const VPRecipeBase *, Type *>(V->getDefiningRecipe())
286           .Case<VPActiveLaneMaskPHIRecipe, VPCanonicalIVPHIRecipe,
287                 VPFirstOrderRecurrencePHIRecipe, VPReductionPHIRecipe,
288                 VPWidenPointerInductionRecipe, VPEVLBasedIVPHIRecipe>(
289               [this](const auto *R) {
290                 // Handle header phi recipes, except VPWidenIntOrFpInduction
291                 // which needs special handling due it being possibly truncated.
292                 // TODO: consider inferring/caching type of siblings, e.g.,
293                 // backedge value, here and in cases below.
294                 return inferScalarType(R->getStartValue());
295               })
296           .Case<VPWidenIntOrFpInductionRecipe, VPDerivedIVRecipe>(
297               [](const auto *R) { return R->getScalarType(); })
298           .Case<VPReductionRecipe, VPPredInstPHIRecipe, VPWidenPHIRecipe,
299                 VPScalarIVStepsRecipe, VPWidenGEPRecipe, VPVectorPointerRecipe,
300                 VPVectorEndPointerRecipe, VPWidenCanonicalIVRecipe>(
301               [this](const VPRecipeBase *R) {
302                 return inferScalarType(R->getOperand(0));
303               })
304           // VPInstructionWithType must be handled before VPInstruction.
305           .Case<VPInstructionWithType, VPWidenIntrinsicRecipe,
306                 VPWidenCastRecipe>(
307               [](const auto *R) { return R->getResultType(); })
308           .Case<VPBlendRecipe, VPInstruction, VPWidenRecipe, VPReplicateRecipe,
309                 VPWidenCallRecipe, VPWidenMemoryRecipe>(
310               [this](const auto *R) { return inferScalarTypeForRecipe(R); })
311           .Case([V](const VPInterleaveBase *R) {
312             // TODO: Use info from interleave group.
313             return V->getUnderlyingValue()->getType();
314           })
315           .Case([](const VPExpandSCEVRecipe *R) {
316             return R->getSCEV()->getType();
317           })
318           .Case([this](const VPReductionRecipe *R) {
319             return inferScalarType(R->getChainOp());
320           })
321           .Case([this](const VPExpressionRecipe *R) {
322             return inferScalarType(R->getOperandOfResultType());
323           });
324 
325   assert(ResultTy && "could not infer type for the given VPValue");
326   CachedTypes[V] = ResultTy;
327   return ResultTy;
328 }
