2227   SmallVector<VPRecipeBase *> WorkList;
2228   SmallPtrSet<VPRecipeBase *, 8> Seen;
2229   Seen.insert(Previous);
2230   auto TryToPushSinkCandidate = [&](VPRecipeBase *SinkCandidate) {
2231     // The previous value must not depend on the users of the recurrence phi. In
2232     // that case, FOR is not a fixed order recurrence.
2233     if (SinkCandidate == Previous)
2234       return false;
2235 
2236     if (isa<VPHeaderPHIRecipe>(SinkCandidate) ||
2237         !Seen.insert(SinkCandidate).second ||
2238         VPDT.properlyDominates(Previous, SinkCandidate))
