435 unsigned VPInstruction::getNumOperandsForOpcode() const {
436   if (Instruction::isUnaryOp(Opcode) || Instruction::isCast(Opcode))
437     return 1;
438 
439   if (Instruction::isBinaryOp(Opcode))
440     return 2;
441 
442   switch (Opcode) {
443   case VPInstruction::StepVector:
444   case VPInstruction::VScale:
445     return 0;
446   case Instruction::Alloca:
447   case Instruction::ExtractValue:
448   case Instruction::Freeze:
449   case Instruction::Load:
450   case VPInstruction::BranchOnCond:
451   case VPInstruction::Broadcast:
452   case VPInstruction::CalculateTripCountMinusVF:
453   case VPInstruction::ExplicitVectorLength:
454   case VPInstruction::ExtractLastLane:
455   case VPInstruction::ExtractLastPart:
456   case VPInstruction::ExtractPenultimateElement:
457   case VPInstruction::Not:
458   case VPInstruction::ResumeForEpilogue:
459   case VPInstruction::Reverse:
460   case VPInstruction::Unpack:
461     return 1;
462   case Instruction::ICmp:
463   case Instruction::FCmp:
464   case Instruction::ExtractElement:
465   case Instruction::Store:
466   case VPInstruction::BranchOnCount:
467   case VPInstruction::BranchOnTwoConds:
468   case VPInstruction::ExitingIVValue:
469   case VPInstruction::FirstOrderRecurrenceSplice:
470   case VPInstruction::LogicalAnd:
471   case VPInstruction::PtrAdd:
472   case VPInstruction::WidePtrAdd:
473   case VPInstruction::WideIVStep:
474     return 2;
475   case Instruction::Select:
476   case VPInstruction::ActiveLaneMask:
477   case VPInstruction::ReductionStartVector:
478   case VPInstruction::ExtractLastActive:
479     return 3;
480   case Instruction::Call: {
481     // For unmasked calls, the last argument will the called function. Use that
482     // to compute the number of operands without the mask.
483     VPValue *LastOp = getOperand(getNumOperands() - 1);
484     if (isa<VPIRValue>(LastOp) && isa<Function>(LastOp->getLiveInIRValue()))
485       return getNumOperands();
486     return getNumOperands() - 1;
487   }
488   case Instruction::GetElementPtr:
489   case Instruction::PHI:
490   case Instruction::Switch:
491   case VPInstruction::AnyOf:
492   case VPInstruction::BuildStructVector:
493   case VPInstruction::BuildVector:
494   case VPInstruction::CanonicalIVIncrementForPart:
495   case VPInstruction::ComputeAnyOfResult:
496   case VPInstruction::ComputeReductionResult:
497   case VPInstruction::FirstActiveLane:
498   case VPInstruction::LastActiveLane:
499   case VPInstruction::SLPLoad:
500   case VPInstruction::SLPStore:
501   case VPInstruction::ExtractLane:
502     // Cannot determine the number of operands from the opcode.
503     return -1u;
504   }
505   llvm_unreachable("all cases should be handled above");
