1357 bool VPInstruction::usesFirstLaneOnly(const VPValue *Op) const {
1358   assert(is_contained(operands(), Op) && "Op must be an operand of the recipe");
1359   if (Instruction::isBinaryOp(getOpcode()) || Instruction::isCast(getOpcode()))
1360     return vputils::onlyFirstLaneUsed(this);
1361 
1362   switch (getOpcode()) {
1363   default:
1364     return false;
1365   case Instruction::ExtractElement:
1366     return Op == getOperand(1);
1367   case Instruction::PHI:
1368     return true;
1369   case Instruction::FCmp:
1370   case Instruction::ICmp:
1371   case Instruction::Select:
1372   case Instruction::Or:
1373   case Instruction::Freeze:
1374   case VPInstruction::Not:
1375     // TODO: Cover additional opcodes.
1376     return vputils::onlyFirstLaneUsed(this);
1377   case VPInstruction::ActiveLaneMask:
1378   case VPInstruction::ExplicitVectorLength:
1379   case VPInstruction::CalculateTripCountMinusVF:
1380   case VPInstruction::CanonicalIVIncrementForPart:
1381   case VPInstruction::BranchOnCount:
1382   case VPInstruction::BranchOnCond:
1383   case VPInstruction::Broadcast:
1384   case VPInstruction::ReductionStartVector:
1385     return true;
1386   case VPInstruction::BuildStructVector:
1387   case VPInstruction::BuildVector:
1388     // Before replicating by VF, Build(Struct)Vector uses all lanes of the
1389     // operand, after replicating its operands only the first lane is used.
1390     // Before replicating, it will have only a single operand.
1391     return getNumOperands() > 1;
