1984 
1985   Value *Address = State.get(getOperand(0));
1986   Value *IncAmt = State.get(getOperand(1), /*IsScalar=*/true);
1987   VectorType *VTy = cast<VectorType>(Address->getType());
1988 
1989   // The histogram intrinsic requires a mask even if the recipe doesn't;
1990   // if the mask operand was omitted then all lanes should be executed and
1991   // we just need to synthesize an all-true mask.
1992   Value *Mask = nullptr;
1993   if (VPValue *VPMask = getMask())
1994     Mask = State.get(VPMask);
1995   else
1996     Mask =
1997         Builder.CreateVectorSplat(VTy->getElementCount(), Builder.getInt1(1));
1998 
1999   // If this is a subtract, we want to invert the increment amount. We may
2000   // add a separate intrinsic in future, but for now we'll try this.
2001   if (Opcode == Instruction::Sub)
2002     IncAmt = Builder.CreateNeg(IncAmt);
2003   else
2004     assert(Opcode == Instruction::Add && "only add or sub supported for now");
2005 
2006   State.Builder.CreateIntrinsic(Intrinsic::experimental_vector_histogram_add,
2007                                 {VTy, IncAmt->getType()},
2008                                 {Address, IncAmt, Mask});
2009 }
