2011 InstructionCost VPHistogramRecipe::computeCost(ElementCount VF,
2012                                                VPCostContext &Ctx) const {
2013   // FIXME: Take the gather and scatter into account as well. For now we're
2014   //        generating the same cost as the fallback path, but we'll likely
2015   //        need to create a new TTI method for determining the cost, including
2016   //        whether we can use base + vec-of-smaller-indices or just
2017   //        vec-of-pointers.
2018   assert(VF.isVector() && "Invalid VF for histogram cost");
2019   Type *AddressTy = Ctx.Types.inferScalarType(getOperand(0));
2020   VPValue *IncAmt = getOperand(1);
2021   Type *IncTy = Ctx.Types.inferScalarType(IncAmt);
2022   VectorType *VTy = VectorType::get(IncTy, VF);
2023 
2024   // Assume that a non-constant update value (or a constant != 1) requires
2025   // a multiply, and add that into the cost.
2026   InstructionCost MulCost =
2027       Ctx.TTI.getArithmeticInstrCost(Instruction::Mul, VTy, Ctx.CostKind);
2028   if (auto *CI = dyn_cast<VPConstantInt>(IncAmt))
2029     if (CI->isOne())
2030       MulCost = TTI::TCC_Free;
2031 
2032   // Find the cost of the histogram operation itself.
2033   Type *PtrTy = VectorType::get(AddressTy, VF);
2034   Type *MaskTy = VectorType::get(Type::getInt1Ty(Ctx.LLVMCtx), VF);
2035   IntrinsicCostAttributes ICA(Intrinsic::experimental_vector_histogram_add,
2036                               Type::getVoidTy(Ctx.LLVMCtx),
2037                               {PtrTy, IncTy, MaskTy});
2038 
2039   // Add the costs together with the add/sub operation.
2040   return Ctx.TTI.getIntrinsicInstrCost(ICA, Ctx.CostKind) + MulCost +
2041          Ctx.TTI.getArithmeticInstrCost(Opcode, VTy, Ctx.CostKind);
2042 }
