2273 void VPWidenRecipe::execute(VPTransformState &State) {
2274   auto &Builder = State.Builder;
2275   switch (Opcode) {
2276   case Instruction::Call:
2277   case Instruction::Br:
2278   case Instruction::PHI:
2279   case Instruction::GetElementPtr:
2280     llvm_unreachable("This instruction is handled by a different recipe.");
2281   case Instruction::UDiv:
2282   case Instruction::SDiv:
2283   case Instruction::SRem:
2284   case Instruction::URem:
2285   case Instruction::Add:
2286   case Instruction::FAdd:
2287   case Instruction::Sub:
2288   case Instruction::FSub:
2289   case Instruction::FNeg:
2290   case Instruction::Mul:
2291   case Instruction::FMul:
2292   case Instruction::FDiv:
2293   case Instruction::FRem:
2294   case Instruction::Shl:
2295   case Instruction::LShr:
2296   case Instruction::AShr:
2297   case Instruction::And:
2298   case Instruction::Or:
2299   case Instruction::Xor: {
2300     // Just widen unops and binops.
2301     SmallVector<Value *, 2> Ops;
2302     for (VPValue *VPOp : operands())
2303       Ops.push_back(State.get(VPOp));
2304 
2305     Value *V = Builder.CreateNAryOp(Opcode, Ops);
2306 
2307     if (auto *VecOp = dyn_cast<Instruction>(V)) {
2308       applyFlags(*VecOp);
2309       applyMetadata(*VecOp);
2310     }
2311 
2312     // Use this vector value for all users of the original instruction.
2313     State.set(this, V);
2314     break;
2315   }
2316   case Instruction::ExtractValue: {
2317     assert(getNumOperands() == 2 && "expected single level extractvalue");
2318     Value *Op = State.get(getOperand(0));
2319     Value *Extract = Builder.CreateExtractValue(
2320         Op, cast<VPConstantInt>(getOperand(1))->getZExtValue());
2321     State.set(this, Extract);
2322     break;
2323   }
2324   case Instruction::Freeze: {
2325     Value *Op = State.get(getOperand(0));
2326     Value *Freeze = Builder.CreateFreeze(Op);
2327     State.set(this, Freeze);
2328     break;
2329   }
2330   case Instruction::ICmp:
2331   case Instruction::FCmp: {
2332     // Widen compares. Generate vector compares.
2333     bool FCmp = Opcode == Instruction::FCmp;
2334     Value *A = State.get(getOperand(0));
2335     Value *B = State.get(getOperand(1));
2336     Value *C = nullptr;
2337     if (FCmp) {
2338       C = Builder.CreateFCmp(getPredicate(), A, B);
2339     } else {
2340       C = Builder.CreateICmp(getPredicate(), A, B);
2341     }
2342     if (auto *I = dyn_cast<Instruction>(C)) {
2343       applyFlags(*I);
2344       applyMetadata(*I);
2345     }
2346     State.set(this, C);
2347     break;
2348   }
2349   case Instruction::Select: {
2350     VPValue *CondOp = getOperand(0);
2351     Value *Cond = State.get(CondOp, vputils::isSingleScalar(CondOp));
2352     Value *Op0 = State.get(getOperand(1));
2353     Value *Op1 = State.get(getOperand(2));
2354     Value *Sel = State.Builder.CreateSelect(Cond, Op0, Op1);
2355     State.set(this, Sel);
2356     if (auto *I = dyn_cast<Instruction>(Sel)) {
2357       if (isa<FPMathOperator>(I))
2358         applyFlags(*I);
2359       applyMetadata(*I);
2360     }
2361     break;
2362   }
2363   default:
2364     // This instruction is not vectorized by simple widening.
2365     LLVM_DEBUG(dbgs() << "LV: Found an unhandled opcode : "
2366                       << Instruction::getOpcodeName(Opcode));
2367     llvm_unreachable("Unhandled instruction!");
2368   } // end of switch.
2369 
2370 #if !defined(NDEBUG)
2371   // Verify that VPlan type inference results agree with the type of the
2372   // generated values.
2373   assert(VectorType::get(State.TypeAnalysis.inferScalarType(this), State.VF) ==
2374              State.get(this)->getType() &&
2375          "inferred type and type from generated instructions do not match");
2376 #endif
2377 }
