2524 void VPScalarIVStepsRecipe::execute(VPTransformState &State) {
2525   // Fast-math-flags propagate from the original induction instruction.
2526   IRBuilder<>::FastMathFlagGuard FMFG(State.Builder);
2527   if (hasFastMathFlags())
2528     State.Builder.setFastMathFlags(getFastMathFlags());
2529 
2530   /// Compute scalar induction steps. \p ScalarIV is the scalar induction
2531   /// variable on which to base the steps, \p Step is the size of the step.
2532 
2533   Value *BaseIV = State.get(getOperand(0), VPLane(0));
2534   Value *Step = State.get(getStepValue(), VPLane(0));
2535   IRBuilderBase &Builder = State.Builder;
2536 
2537   // Ensure step has the same type as that of scalar IV.
2538   Type *BaseIVTy = BaseIV->getType()->getScalarType();
2539   assert(BaseIVTy == Step->getType() && "Types of BaseIV and Step must match!");
2540 
2541   // We build scalar steps for both integer and floating-point induction
2542   // variables. Here, we determine the kind of arithmetic we will perform.
2543   Instruction::BinaryOps AddOp;
2544   Instruction::BinaryOps MulOp;
2545   if (BaseIVTy->isIntegerTy()) {
2546     AddOp = Instruction::Add;
2547     MulOp = Instruction::Mul;
2548   } else {
2549     AddOp = InductionOpcode;
2550     MulOp = Instruction::FMul;
2551   }
2552 
2553   // Determine the number of scalars we need to generate.
2554   bool FirstLaneOnly = vputils::onlyFirstLaneUsed(this);
2555   // Compute the scalar steps and save the results in State.
2556 
2557   unsigned StartLane = 0;
2558   unsigned EndLane = FirstLaneOnly ? 1 : State.VF.getKnownMinValue();
2559   if (State.Lane) {
2560     StartLane = State.Lane->getKnownLane();
2561     EndLane = StartLane + 1;
2562   }
2563   Value *StartIdx0 = getStartIndex() ? State.get(getStartIndex(), true)
2564                                      : Constant::getNullValue(BaseIVTy);
2565 
2566   for (unsigned Lane = StartLane; Lane < EndLane; ++Lane) {
2567     // It is okay if the induction variable type cannot hold the lane number,
2568     // we expect truncation in this case.
2569     Constant *LaneValue =
2570         BaseIVTy->isIntegerTy()
2571             ? ConstantInt::get(BaseIVTy, Lane, /*IsSigned=*/false,
2572                                /*ImplicitTrunc=*/true)
2573             : ConstantFP::get(BaseIVTy, Lane);
2574     Value *StartIdx = Builder.CreateBinOp(AddOp, StartIdx0, LaneValue);
2575     // The step returned by `createStepForVF` is a runtime-evaluated value
2576     // when VF is scalable. Otherwise, it should be folded into a Constant.
2577     assert((State.VF.isScalable() || isa<Constant>(StartIdx)) &&
2578            "Expected StartIdx to be folded to a constant when VF is not "
2579            "scalable");
2580     auto *Mul = Builder.CreateBinOp(MulOp, StartIdx, Step);
2581     auto *Add = Builder.CreateBinOp(AddOp, BaseIV, Mul);
2582     State.set(this, Add, VPLane(Lane));
2583   }
