2601 void VPWidenGEPRecipe::execute(VPTransformState &State) {
2602   assert(State.VF.isVector() && "not widening");
2603   // Construct a vector GEP by widening the operands of the scalar GEP as
2604   // necessary. We mark the vector GEP 'inbounds' if appropriate. A GEP
2605   // results in a vector of pointers when at least one operand of the GEP
2606   // is vector-typed. Thus, to keep the representation compact, we only use
2607   // vector-typed operands for loop-varying values.
2608 
2609   bool AllOperandsAreInvariant = all_of(operands(), [](VPValue *Op) {
2610     return Op->isDefinedOutsideLoopRegions();
2611   });
2612   if (AllOperandsAreInvariant) {
2613     // If we are vectorizing, but the GEP has only loop-invariant operands,
2614     // the GEP we build (by only using vector-typed operands for
2615     // loop-varying values) would be a scalar pointer. Thus, to ensure we
2616     // produce a vector of pointers, we need to either arbitrarily pick an
2617     // operand to broadcast, or broadcast a clone of the original GEP.
2618     // Here, we broadcast a clone of the original.
2619 
2620     SmallVector<Value *> Ops;
2621     for (unsigned I = 0, E = getNumOperands(); I != E; I++)
2622       Ops.push_back(State.get(getOperand(I), VPLane(0)));
2623 
2624     auto *NewGEP =
2625         State.Builder.CreateGEP(getSourceElementType(), Ops[0], drop_begin(Ops),
2626                                 "", getGEPNoWrapFlags());
2627     Value *Splat = State.Builder.CreateVectorSplat(State.VF, NewGEP);
2628     State.set(this, Splat);
2629     return;
2630   }
2631 
2632   // If the GEP has at least one loop-varying operand, we are sure to
2633   // produce a vector of pointers unless VF is scalar.
2634   // The pointer operand of the new GEP. If it's loop-invariant, we
2635   // won't broadcast it.
2636   auto *Ptr = State.get(getOperand(0), isPointerLoopInvariant());
2637 
2638   // Collect all the indices for the new GEP. If any index is
2639   // loop-invariant, we won't broadcast it.
2640   SmallVector<Value *, 4> Indices;
2641   for (unsigned I = 1, E = getNumOperands(); I < E; I++) {
2642     VPValue *Operand = getOperand(I);
2643     Indices.push_back(State.get(Operand, isIndexLoopInvariant(I - 1)));
2644   }
2645 
2646   // Create the new GEP. Note that this GEP may be a scalar if VF == 1,
2647   // but it should be a vector, otherwise.
2648   auto *NewGEP = State.Builder.CreateGEP(getSourceElementType(), Ptr, Indices,
2649                                          "", getGEPNoWrapFlags());
