354 static VPValue *getPredicatedMask(VPRegionBlock *R) {
355   auto *EntryBB = dyn_cast<VPBasicBlock>(R->getEntry());
356   if (!EntryBB || EntryBB->size() != 1 ||
357       !isa<VPBranchOnMaskRecipe>(EntryBB->begin()))
358     return nullptr;
