2818 // Add a VPActiveLaneMaskPHIRecipe and related recipes to \p Plan and replace
2819 // the loop terminator with a branch-on-cond recipe with the negated
2820 // active-lane-mask as operand. Note that this turns the loop into an
2821 // uncountable one. Only the existing terminator is replaced, all other existing
2822 // recipes/users remain unchanged, except for poison-generating flags being
2823 // dropped from the canonical IV increment. Return the created
2824 // VPActiveLaneMaskPHIRecipe.
2825 //
2826 // The function uses the following definitions:
2827 //
2828 //  %TripCount = DataWithControlFlowWithoutRuntimeCheck ?
2829 //    calculate-trip-count-minus-VF (original TC) : original TC
2830 //  %IncrementValue = DataWithControlFlowWithoutRuntimeCheck ?
2831 //     CanonicalIVPhi : CanonicalIVIncrement
2832 //  %StartV is the canonical induction start value.
2833 //
2834 // The function adds the following recipes:
2835 //
2836 // vector.ph:
2837 //   %TripCount = calculate-trip-count-minus-VF (original TC)
2838 //       [if DataWithControlFlowWithoutRuntimeCheck]
2839 //   %EntryInc = canonical-iv-increment-for-part %StartV
2840 //   %EntryALM = active-lane-mask %EntryInc, %TripCount
2841 //
2842 // vector.body:
2843 //   ...
2844 //   %P = active-lane-mask-phi [ %EntryALM, %vector.ph ], [ %ALM, %vector.body ]
2845 //   ...
2846 //   %InLoopInc = canonical-iv-increment-for-part %IncrementValue
2847 //   %ALM = active-lane-mask %InLoopInc, TripCount
2848 //   %Negated = Not %ALM
2849 //   branch-on-cond %Negated
2850 //
2851 static VPActiveLaneMaskPHIRecipe *addVPLaneMaskPhiAndUpdateExitBranch(
2852     VPlan &Plan, bool DataAndControlFlowWithoutRuntimeCheck) {
2853   VPRegionBlock *TopRegion = Plan.getVectorLoopRegion();
2854   VPBasicBlock *EB = TopRegion->getExitingBasicBlock();
2855   auto *CanonicalIVPHI = TopRegion->getCanonicalIV();
2856   VPValue *StartV = CanonicalIVPHI->getStartValue();
2857 
2858   auto *CanonicalIVIncrement =
2859       cast<VPInstruction>(CanonicalIVPHI->getBackedgeValue());
2860   // TODO: Check if dropping the flags is needed if
2861   // !DataAndControlFlowWithoutRuntimeCheck.
2862   CanonicalIVIncrement->dropPoisonGeneratingFlags();
2863   DebugLoc DL = CanonicalIVIncrement->getDebugLoc();
2864   // We can't use StartV directly in the ActiveLaneMask VPInstruction, since
2865   // we have to take unrolling into account. Each part needs to start at
2866   //   Part * VF
2867   auto *VecPreheader = Plan.getVectorPreheader();
2868   VPBuilder Builder(VecPreheader);
2869 
2870   // Create the ActiveLaneMask instruction using the correct start values.
2871   VPValue *TC = Plan.getTripCount();
2872 
2873   VPValue *TripCount, *IncrementValue;
2874   if (!DataAndControlFlowWithoutRuntimeCheck) {
2875     // When the loop is guarded by a runtime overflow check for the loop
2876     // induction variable increment by VF, we can increment the value before
2877     // the get.active.lane mask and use the unmodified tripcount.
2878     IncrementValue = CanonicalIVIncrement;
2879     TripCount = TC;
2880   } else {
2881     // When avoiding a runtime check, the active.lane.mask inside the loop
2882     // uses a modified trip count and the induction variable increment is
2883     // done after the active.lane.mask intrinsic is called.
2884     IncrementValue = CanonicalIVPHI;
2885     TripCount = Builder.createNaryOp(VPInstruction::CalculateTripCountMinusVF,
2886                                      {TC}, DL);
2887   }
2888   auto *EntryIncrement = Builder.createOverflowingOp(
2889       VPInstruction::CanonicalIVIncrementForPart, {StartV}, {false, false}, DL,
2890       "index.part.next");
2891 
2892   // Create the active lane mask instruction in the VPlan preheader.
2893   VPValue *ALMMultiplier =
2894       Plan.getConstantInt(TopRegion->getCanonicalIVType(), 1);
2895   auto *EntryALM = Builder.createNaryOp(VPInstruction::ActiveLaneMask,
2896                                         {EntryIncrement, TC, ALMMultiplier}, DL,
2897                                         "active.lane.mask.entry");
2898 
2899   // Now create the ActiveLaneMaskPhi recipe in the main loop using the
2900   // preheader ActiveLaneMask instruction.
2901   auto *LaneMaskPhi =
2902       new VPActiveLaneMaskPHIRecipe(EntryALM, DebugLoc::getUnknown());
2903   LaneMaskPhi->insertAfter(CanonicalIVPHI);
2904 
2905   // Create the active lane mask for the next iteration of the loop before the
2906   // original terminator.
2907   VPRecipeBase *OriginalTerminator = EB->getTerminator();
2908   Builder.setInsertPoint(OriginalTerminator);
2909   auto *InLoopIncrement =
2910       Builder.createOverflowingOp(VPInstruction::CanonicalIVIncrementForPart,
2911                                   {IncrementValue}, {false, false}, DL);
2912   auto *ALM = Builder.createNaryOp(VPInstruction::ActiveLaneMask,
2913                                    {InLoopIncrement, TripCount, ALMMultiplier},
2914                                    DL, "active.lane.mask.next");
2915   LaneMaskPhi->addOperand(ALM);
2916 
2917   // Replace the original terminator with BranchOnCond. We have to invert the
2918   // mask here because a true condition means jumping to the exit block.
2919   auto *NotMask = Builder.createNot(ALM, DL);
2920   Builder.createNaryOp(VPInstruction::BranchOnCond, {NotMask}, DL);
2921   OriginalTerminator->eraseFromParent();
2922   return LaneMaskPhi;
2923 }
