2925 void VPlanTransforms::addActiveLaneMask(
2926     VPlan &Plan, bool UseActiveLaneMaskForControlFlow,
2927     bool DataAndControlFlowWithoutRuntimeCheck) {
2928   assert((!DataAndControlFlowWithoutRuntimeCheck ||
2929           UseActiveLaneMaskForControlFlow) &&
2930          "DataAndControlFlowWithoutRuntimeCheck implies "
2931          "UseActiveLaneMaskForControlFlow");
2932 
2933   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
2934   auto *FoundWidenCanonicalIVUser = find_if(
2935       LoopRegion->getCanonicalIV()->users(), IsaPred<VPWidenCanonicalIVRecipe>);
2936   assert(FoundWidenCanonicalIVUser &&
2937          "Must have widened canonical IV when tail folding!");
2938   VPSingleDefRecipe *HeaderMask = vputils::findHeaderMask(Plan);
2939   auto *WideCanonicalIV =
2940       cast<VPWidenCanonicalIVRecipe>(*FoundWidenCanonicalIVUser);
2941   VPSingleDefRecipe *LaneMask;
2942   if (UseActiveLaneMaskForControlFlow) {
2943     LaneMask = addVPLaneMaskPhiAndUpdateExitBranch(
2944         Plan, DataAndControlFlowWithoutRuntimeCheck);
2945   } else {
2946     VPBuilder B = VPBuilder::getToInsertAfter(WideCanonicalIV);
2947     VPValue *ALMMultiplier = Plan.getOrAddLiveIn(
2948         ConstantInt::get(LoopRegion->getCanonicalIVType(), 1));
2949     LaneMask =
2950         B.createNaryOp(VPInstruction::ActiveLaneMask,
2951                        {WideCanonicalIV, Plan.getTripCount(), ALMMultiplier},
2952                        nullptr, "active.lane.mask");
2953   }
2954 
2955   // Walk users of WideCanonicalIV and replace the header mask of the form
2956   // (ICMP_ULE, WideCanonicalIV, backedge-taken-count) with an active-lane-mask,
2957   // removing the old one to ensure there is always only a single header mask.
2958   HeaderMask->replaceAllUsesWith(LaneMask);
2959   HeaderMask->eraseFromParent();
2960 }
