1112 InstructionCost VPInstruction::computeCost(ElementCount VF,
1113                                            VPCostContext &Ctx) const {
1114   if (Instruction::isBinaryOp(getOpcode())) {
1115     if (!getUnderlyingValue() && getOpcode() != Instruction::FMul) {
1116       // TODO: Compute cost for VPInstructions without underlying values once
1117       // the legacy cost model has been retired.
1118       return 0;
1119     }
1120 
1121     assert(!doesGeneratePerAllLanes() &&
1122            "Should only generate a vector value or single scalar, not scalars "
1123            "for all lanes.");
1124     return getCostForRecipeWithOpcode(
1125         getOpcode(),
1126         vputils::onlyFirstLaneUsed(this) ? ElementCount::getFixed(1) : VF, Ctx);
1127   }
1128 
1129   switch (getOpcode()) {
1130   case Instruction::Select: {
1131     llvm::CmpPredicate Pred = CmpInst::BAD_ICMP_PREDICATE;
1132     match(getOperand(0), m_Cmp(Pred, m_VPValue(), m_VPValue()));
1133     auto *CondTy = Ctx.Types.inferScalarType(getOperand(0));
1134     auto *VecTy = Ctx.Types.inferScalarType(getOperand(1));
1135     if (!vputils::onlyFirstLaneUsed(this)) {
1136       CondTy = toVectorTy(CondTy, VF);
1137       VecTy = toVectorTy(VecTy, VF);
1138     }
1139     return Ctx.TTI.getCmpSelInstrCost(Instruction::Select, VecTy, CondTy, Pred,
1140                                       Ctx.CostKind);
1141   }
1142   case Instruction::ExtractElement:
1143   case VPInstruction::ExtractLane: {
1144     if (VF.isScalar()) {
1145       // ExtractLane with VF=1 takes care of handling extracting across multiple
1146       // parts.
1147       return 0;
1148     }
1149 
1150     // Add on the cost of extracting the element.
1151     auto *VecTy = toVectorTy(Ctx.Types.inferScalarType(getOperand(0)), VF);
1152     return Ctx.TTI.getVectorInstrCost(Instruction::ExtractElement, VecTy,
1153                                       Ctx.CostKind);
1154   }
1155   case VPInstruction::AnyOf: {
1156     auto *VecTy = toVectorTy(Ctx.Types.inferScalarType(this), VF);
1157     return Ctx.TTI.getArithmeticReductionCost(
1158         Instruction::Or, cast<VectorType>(VecTy), std::nullopt, Ctx.CostKind);
1159   }
1160   case VPInstruction::FirstActiveLane: {
1161     Type *ScalarTy = Ctx.Types.inferScalarType(getOperand(0));
1162     if (VF.isScalar())
1163       return Ctx.TTI.getCmpSelInstrCost(Instruction::ICmp, ScalarTy,
1164                                         CmpInst::makeCmpResultType(ScalarTy),
1165                                         CmpInst::ICMP_EQ, Ctx.CostKind);
1166     // Calculate the cost of determining the lane index.
1167     auto *PredTy = toVectorTy(ScalarTy, VF);
1168     IntrinsicCostAttributes Attrs(Intrinsic::experimental_cttz_elts,
1169                                   Type::getInt64Ty(Ctx.LLVMCtx),
1170                                   {PredTy, Type::getInt1Ty(Ctx.LLVMCtx)});
1171     return Ctx.TTI.getIntrinsicInstrCost(Attrs, Ctx.CostKind);
1172   }
1173   case VPInstruction::LastActiveLane: {
1174     Type *ScalarTy = Ctx.Types.inferScalarType(getOperand(0));
1175     if (VF.isScalar())
1176       return Ctx.TTI.getCmpSelInstrCost(Instruction::ICmp, ScalarTy,
1177                                         CmpInst::makeCmpResultType(ScalarTy),
1178                                         CmpInst::ICMP_EQ, Ctx.CostKind);
1179     // Calculate the cost of determining the lane index: NOT + cttz_elts + SUB.
1180     auto *PredTy = toVectorTy(ScalarTy, VF);
1181     IntrinsicCostAttributes Attrs(Intrinsic::experimental_cttz_elts,
1182                                   Type::getInt64Ty(Ctx.LLVMCtx),
1183                                   {PredTy, Type::getInt1Ty(Ctx.LLVMCtx)});
1184     InstructionCost Cost = Ctx.TTI.getIntrinsicInstrCost(Attrs, Ctx.CostKind);
1185     // Add cost of NOT operation on the predicate.
1186     Cost += Ctx.TTI.getArithmeticInstrCost(
1187         Instruction::Xor, PredTy, Ctx.CostKind,
1188         {TargetTransformInfo::OK_AnyValue, TargetTransformInfo::OP_None},
1189         {TargetTransformInfo::OK_UniformConstantValue,
1190          TargetTransformInfo::OP_None});
1191     // Add cost of SUB operation on the index.
1192     Cost += Ctx.TTI.getArithmeticInstrCost(
1193         Instruction::Sub, Type::getInt64Ty(Ctx.LLVMCtx), Ctx.CostKind);
1194     return Cost;
1195   }
1196   case VPInstruction::ExtractLastActive: {
1197     Type *ScalarTy = Ctx.Types.inferScalarType(this);
1198     Type *VecTy = toVectorTy(ScalarTy, VF);
1199     Type *MaskTy = toVectorTy(Type::getInt1Ty(Ctx.LLVMCtx), VF);
1200     IntrinsicCostAttributes ICA(
1201         Intrinsic::experimental_vector_extract_last_active, ScalarTy,
1202         {VecTy, MaskTy, ScalarTy});
1203     return Ctx.TTI.getIntrinsicInstrCost(ICA, Ctx.CostKind);
1204   }
1205   case VPInstruction::FirstOrderRecurrenceSplice: {
1206     assert(VF.isVector() && "Scalar FirstOrderRecurrenceSplice?");
1207     SmallVector<int> Mask(VF.getKnownMinValue());
1208     std::iota(Mask.begin(), Mask.end(), VF.getKnownMinValue() - 1);
1209     Type *VectorTy = toVectorTy(Ctx.Types.inferScalarType(this), VF);
1210 
1211     return Ctx.TTI.getShuffleCost(TargetTransformInfo::SK_Splice,
1212                                   cast<VectorType>(VectorTy),
1213                                   cast<VectorType>(VectorTy), Mask,
1214                                   Ctx.CostKind, VF.getKnownMinValue() - 1);
1215   }
1216   case VPInstruction::ActiveLaneMask: {
1217     Type *ArgTy = Ctx.Types.inferScalarType(getOperand(0));
1218     unsigned Multiplier = cast<VPConstantInt>(getOperand(2))->getZExtValue();
1219     Type *RetTy = toVectorTy(Type::getInt1Ty(Ctx.LLVMCtx), VF * Multiplier);
1220     IntrinsicCostAttributes Attrs(Intrinsic::get_active_lane_mask, RetTy,
1221                                   {ArgTy, ArgTy});
1222     return Ctx.TTI.getIntrinsicInstrCost(Attrs, Ctx.CostKind);
1223   }
1224   case VPInstruction::ExplicitVectorLength: {
1225     Type *Arg0Ty = Ctx.Types.inferScalarType(getOperand(0));
1226     Type *I32Ty = Type::getInt32Ty(Ctx.LLVMCtx);
1227     Type *I1Ty = Type::getInt1Ty(Ctx.LLVMCtx);
1228     IntrinsicCostAttributes Attrs(Intrinsic::experimental_get_vector_length,
1229                                   I32Ty, {Arg0Ty, I32Ty, I1Ty});
1230     return Ctx.TTI.getIntrinsicInstrCost(Attrs, Ctx.CostKind);
1231   }
1232   case VPInstruction::Reverse: {
1233     assert(VF.isVector() && "Reverse operation must be vector type");
1234     auto *VectorTy = cast<VectorType>(
1235         toVectorTy(Ctx.Types.inferScalarType(getOperand(0)), VF));
1236     return Ctx.TTI.getShuffleCost(TargetTransformInfo::SK_Reverse, VectorTy,
1237                                   VectorTy, /*Mask=*/{}, Ctx.CostKind,
1238                                   /*Index=*/0);
1239   }
1240   case VPInstruction::ExtractLastLane: {
1241     // Add on the cost of extracting the element.
1242     auto *VecTy = toVectorTy(Ctx.Types.inferScalarType(getOperand(0)), VF);
1243     return Ctx.TTI.getIndexedVectorInstrCostFromEnd(Instruction::ExtractElement,
1244                                                     VecTy, Ctx.CostKind, 0);
1245   }
1246   case VPInstruction::ExtractPenultimateElement:
1247     if (VF == ElementCount::getScalable(1))
1248       return InstructionCost::getInvalid();
1249     [[fallthrough]];
1250   default:
1251     // TODO: Compute cost other VPInstructions once the legacy cost model has
1252     // been retired.
1253     assert(!getUnderlyingValue() &&
1254            "unexpected VPInstruction witht underlying value");
1255     return 0;
1256   }
1257 }
